label("$A$",(-0.3,0.94),NW);
dot((-0.3,0.94));
label("$B$",(0.7,-0.7),SE);
dot((0.7,-0.7));
label("$C$",(0.3,-0.94),SSE);
dot((0.3,-0.94));
label("$D$",(-0.7,-0.7),SW);
